mapper.select:
		select * ,
		deliveryUser.nx_CU_user_id 'delivery_nx_CU_user_id',
		deliveryUser.nx_CU_join_date 'delivery_nx_CU_join_date',
		deliveryUser.nx_CU_order_amount 'delivery_nx_CU_order_amount',
		deliveryUser.nx_CU_order_times 'delivery_nx_CU_order_times',
		deliveryUser.nx_CU_customer_id 'delivery_nx_CU_customer_id',
		deliveryUser.nx_CU_wx_avatar_url 'delivery_nx_CU_wx_avatar_url',
		deliveryUser.nx_CU_wx_nick_name 'delivery_nx_CU_wx_nick_name',
		deliveryUser.nx_CU_wx_phone_number 'delivery_nx_CU_wx_phone_number',

		deliveryCus.nx_customer_id 'delivery_nx_customer_id',
		deliveryCus.nx_customer_card_waste_date 'delivery_nx_customer_card_waste_date'
		from nx_community_orders as o
		left join nx_community_splicing_orders as sp on sp.nx_cso_co_order_id = o.nx_community_orders_id
			left join nx_community_orders_sub as s on s.nx_COS_orders_id = o.nx_community_orders_id
		    left join nx_customer_user as deliveryUser on deliveryUser.nx_CU_user_id = o.nx_CO_user_id
		left join nx_customer   as deliveryCus on deliveryCus.nx_customer_id = deliveryUser.nx_CU_customer_id

		left join nx_community_goods as ncg  on ncg.nx_community_goods_id = s.nx_COS_community_goods_id
		left join nx_customer_user_card as ncuc on ncuc.nx_cuca_com_order_id = o.nx_community_orders_id
		left join nx_community_card as ncc  on ncc.nx_community_card_id = ncuc.nx_cuca_card_id
		left join nx_customer_user_address as ncua on ncua.nx_customer_user_address_id = o.nx_CO_delivery_address_id



				and o.nx_CO_wx_out_trade_no = #{trade_no}


				and o.nx_community_orders_id = #{id}


				and o.nx_CO_desk_id =  #{deskId}


				and o.nx_CO_community_id = #{commId}


				and o.nx_CO_service_date > #{startDate}


				and o.nx_CO_service_date < #{stopDate}


				and o.nx_CO_service_date = #{date}



				and o.nx_CO_user_id = #{orderUserId}


				and o.nx_CO_delivery_user_id = #{deliveryUserId}


				and o.nx_CO_status = #{status}


				and o.nx_CO_status > #{dayuStatus}


          order by nx_community_orders_id DESC

		select *
		       from nx_community_orders as o
		left join nx_customer_user as orderUser on orderUser.nx_CU_user_id = o.nx_CO_user_id



				and o.nx_community_orders_id = #{id}


				and o.nx_CO_desk_id =  #{deskId}


				and o.nx_CO_community_id = #{commId}


				and o.nx_CO_user_id = #{orderUserId}


				and o.nx_CO_delivery_user_id = #{deliveryUserId}


				and o.nx_CO_status = #{status}


				and o.nx_CO_status < #{xiaoyuStatus}


				and o.nx_CO_type = #{type}


        order by nx_community_orders_id DESC

select *, deliveryUser.nx_CU_user_id 'delivery_nx_CU_user_id', deliveryUser.nx_CU_join_date 'delivery_nx_CU_join_date', deliveryUser.nx_CU_order_amount 'delivery_nx_CU_order_amount', deliveryUser.nx_CU_order_times 'delivery_nx_CU_order_times', deliveryUser.nx_CU_customer_id 'delivery_nx_CU_customer_id', deliveryUser.nx_CU_wx_avatar_url 'delivery_nx_CU_wx_avatar_url', deliveryUser.nx_CU_wx_nick_name 'delivery_nx_CU_wx_nick_name', deliveryUser.nx_CU_wx_phone_number 'delivery_nx_CU_wx_phone_number', deliveryCus.nx_customer_id 'delivery_nx_customer_id', deliveryCus.nx_customer_card_waste_date 'delivery_nx_customer_card_waste_date',
spOrderUser.nx_CU_user_id 'splicing_nx_CU_user_id', spOrderUser.nx_CU_customer_id 'splicing_nx_CU_customer_id', spOrderUser.nx_CU_wx_avatar_url 'splicing_nx_CU_wx_avatar_url', spOrderUser.nx_CU_wx_nick_name 'splicing_nx_CU_wx_nick_name', spOrderCus.nx_customer_id 'splicing_nx_customer_id', spOrderCus.nx_customer_card_waste_date 'splicing_nx_customer_card_waste_date',
spOs.nx_community_orders_sub_id 'spOs_nx_community_orders_sub_id', spOs.nx_COS_service_type 'spOs_nx_COS_service_type', spOs.nx_COS_service 'spOs_nx_COS_service', spOs.nx_COS_service_date 'spOs_nx_COS_service_date', spOs.nx_COS_service_time 'spOs_nx_COS_service_time', spOs.nx_COS_goods_index 'spOs_nx_COS_goods_index', spOs.nx_COS_community_goods_id 'spOs_nx_COS_community_goods_id', spOs.nx_COS_order_user_id 'spOs_nx_COS_order_user_id', spOs.nx_COS_status 'spOs_nx_COS_status', spOs.nx_COS_type 'spOs_nx_COS_type', spOs.nx_COS_orders_id 'spOs_nx_COS_orders_id', spOs.nx_COS_huaxian_different_price 'spOs_nx_COS_huaxian_different_price', spOs.nx_COS_huaxian_price 'spOs_nx_COS_huaxian_price', spOs.nx_COS_price 'spOs_nx_COS_price', spOs.nx_COS_quantity 'spOs_nx_COS_quantity', spOs.nx_COS_standard 'spOs_nx_COS_standard', spOs.nx_COS_subtotal 'spOs_nx_COS_subtotal', spOs.nx_COS_remark 'spOs_nx_COS_remark', spCg.nx_community_goods_id 'spCg_nx_community_goods_id', spCg.nx_cg_goods_name 'spCg_nx_cg_goods_name', spCg.nx_cg_goods_standardname 'spCg_nx_cg_goods_standardname'
from nx_community_orders as o left join nx_customer_user_card as ncuc on ncuc.nx_cuca_com_order_id = o.nx_community_orders_id left join nx_community_card as ncc on ncc.nx_community_card_id = ncuc.nx_cuca_card_id left join nx_customer as dc on o.nx_CO_customer_id = dc.nx_customer_id left join nx_customer_user as ou on o.nx_CO_user_id = ou.nx_CU_user_id
left join nx_customer_user as du on o.nx_CO_delivery_user_id = du.nx_CU_user_id left join nx_community_orders_sub as os on o.nx_community_orders_id = os.nx_COS_orders_id left join nx_community_goods as cg on cg.nx_community_goods_id = os.nx_COS_community_goods_id
left join nx_community_splicing_orders as sp on sp.nx_cso_co_order_id = o.nx_community_orders_id and sp.nx_cso_total > 0 left join nx_customer_user as spOrderUser on sp.nx_cso_user_id = spOrderUser.nx_CU_user_id
left join nx_community_orders_sub as spOs on sp.nx_community_splicing_orders_id = spOs.nx_COS_splicing_orders_id and spOs.nx_COS_order_user_id = sp.nx_cso_user_id left join nx_community_goods as spCg on spCg.nx_community_goods_id = spOs.nx_COS_community_goods_id
left join nx_customer as spOrderCus on spOrderCus.nx_customer_id = spOrderUser.nx_CU_customer_id left join nx_customer_user as deliveryUser on deliveryUser.nx_CU_user_id = o.nx_CO_delivery_user_id left join nx_customer as deliveryCus on deliveryCus.nx_customer_id = deliveryUser.nx_CU_customer_id left join nx_customer_user_address as ncua on ncua.nx_customer_user_address_id = o.nx_CO_delivery_address_id
and o.nx_CO_community_id = #{commId}
and o.nx_CO_status < #{xiaoyuStatus}
and o.nx_CO_status = #{status}
and o.nx_CO_type = #{type}
and o.nx_CO_user_id = #{deliveryUserId}
and o.nx_community_orders_id = #{id}
and o.nx_CO_desk_id = #{deskId}
order by o.nx_CO_service, o.nx_CO_service_date, o.nx_CO_service_time, os.nx_COS_status, os.nx_community_orders_sub_id

select *, deliveryUser.nx_CU_user_id 'delivery_nx_CU_user_id', deliveryUser.nx_CU_join_date 'delivery_nx_CU_join_date', deliveryUser.nx_CU_order_amount 'delivery_nx_CU_order_amount', deliveryUser.nx_CU_order_times 'delivery_nx_CU_order_times', deliveryUser.nx_CU_customer_id 'delivery_nx_CU_customer_id', deliveryUser.nx_CU_wx_avatar_url 'delivery_nx_CU_wx_avatar_url', deliveryUser.nx_CU_wx_nick_name 'delivery_nx_CU_wx_nick_name', deliveryUser.nx_CU_wx_phone_number 'delivery_nx_CU_wx_phone_number', deliveryCus.nx_customer_id 'delivery_nx_customer_id', deliveryCus.nx_customer_card_waste_date 'delivery_nx_customer_card_waste_date',
asOrderUser.nx_CU_user_id 'splicing_nx_CU_user_id', asOrderUser.nx_CU_customer_id 'splicing_nx_CU_customer_id', asOrderUser.nx_CU_wx_avatar_url 'splicing_nx_CU_wx_avatar_url', asOrderUser.nx_CU_wx_nick_name 'splicing_nx_CU_wx_nick_name', asOrderCus.nx_customer_id 'splicing_nx_customer_id', asOrderCus.nx_customer_card_waste_date 'splicing_nx_customer_card_waste_date',
spOs.nx_community_orders_sub_id 'spOs_nx_community_orders_sub_id', spOs.nx_COS_service_type 'spOs_nx_COS_service_type', spOs.nx_COS_service 'spOs_nx_COS_service', spOs.nx_COS_service_date 'spOs_nx_COS_service_date', spOs.nx_COS_service_time 'spOs_nx_COS_service_time', spOs.nx_COS_goods_index 'spOs_nx_COS_goods_index', spOs.nx_COS_community_goods_id 'spOs_nx_COS_community_goods_id', spOs.nx_COS_order_user_id 'spOs_nx_COS_order_user_id', spOs.nx_COS_status 'spOs_nx_COS_status', spOs.nx_COS_type 'spOs_nx_COS_type', spOs.nx_COS_orders_id 'spOs_nx_COS_orders_id', spOs.nx_COS_huaxian_different_price 'spOs_nx_COS_huaxian_different_price', spOs.nx_COS_huaxian_price 'spOs_nx_COS_huaxian_price', spOs.nx_COS_price 'spOs_nx_COS_price', spOs.nx_COS_quantity 'spOs_nx_COS_quantity', spOs.nx_COS_standard 'spOs_nx_COS_standard', spOs.nx_COS_subtotal 'spOs_nx_COS_subtotal', spOs.nx_COS_remark 'spOs_nx_COS_remark', spCg.nx_community_goods_id 'spCg_nx_community_goods_id', spCg.nx_cg_goods_name 'spCg_nx_cg_goods_name', spCg.nx_cg_goods_standardname 'spCg_nx_cg_goods_standardname'
from nx_community_orders as nco left join nx_community_splicing_orders as ncso on ncso.nx_cso_co_order_id = nco.nx_community_orders_id left join nx_community_orders_sub as spOs on spOs.nx_COS_splicing_orders_id = ncso.nx_community_splicing_orders_id and spOs.nx_COS_type = #{orderType}
left join nx_customer_user_goods as ncug on ncug.nx_CUG_community_goods_id = spOs.nx_COS_community_goods_id and nx_CUG_user_id = spOs.nx_COS_order_user_id left join nx_customer_user as asOrderUser on asOrderUser.nx_CU_user_id = ncso.nx_cso_user_id left join nx_customer as asOrderCus on asOrderCus.nx_customer_id = asOrderUser.nx_CU_customer_id left join nx_customer_user_card as nccc on nccc.nx_cuca_customer_user_id = ncso.nx_cso_user_id and nccc.nx_cuca_status = -1 and nccc.nx_cuca_is_selected = 1 and nccc.nx_cuca_type = #{orderType} left join nx_community_card as ncc on ncc.nx_community_card_id = nccc.nx_cuca_card_id left join nx_community_goods as spCg on spCg.nx_community_goods_id = spOs.nx_COS_community_goods_id left join nx_customer_user as deliveryUser on deliveryUser.nx_CU_user_id = nco.nx_CO_delivery_user_id left join nx_customer as deliveryCus on deliveryCus.nx_customer_id = deliveryUser.nx_CU_customer_id left join nx_customer_user_address as ncua on ncua.nx_customer_user_address_id = nco.nx_CO_delivery_address_id
and nco.nx_community_orders_id = #{id}
and o.nx_CO_desk_id = #{deskId}
and nco.nx_CO_service_type = #{serviceType}
and nco.nx_CO_delivery_user_id = #{deliveryUserId}
and ncso.nx_cso_user_id != #{notEqualOrderUserId}
and nco.nx_CO_status = #{status}

select *, deliveryUser.nx_CU_user_id 'delivery_nx_CU_user_id', deliveryUser.nx_CU_join_date 'delivery_nx_CU_join_date', deliveryUser.nx_CU_order_amount 'delivery_nx_CU_order_amount', deliveryUser.nx_CU_order_times 'delivery_nx_CU_order_times', deliveryUser.nx_CU_customer_id 'delivery_nx_CU_customer_id', deliveryUser.nx_CU_wx_avatar_url 'delivery_nx_CU_wx_avatar_url', deliveryUser.nx_CU_wx_nick_name 'delivery_nx_CU_wx_nick_name', deliveryUser.nx_CU_wx_phone_number 'delivery_nx_CU_wx_phone_number', deliveryCus.nx_customer_id 'delivery_nx_customer_id', deliveryCus.nx_customer_card_waste_date 'delivery_nx_customer_card_waste_date' from nx_community_orders as o left join nx_customer_user_card as ncuc on ncuc.nx_cuca_com_order_id = o.nx_community_orders_id left join nx_community_card as ncc on ncc.nx_community_card_id = ncuc.nx_cuca_card_id left join nx_customer as dc on o.nx_CO_customer_id = dc.nx_customer_id left join nx_customer_user as du on o.nx_CO_delivery_user_id = du.nx_CU_user_id left join nx_community_orders_sub as os on o.nx_community_orders_id = os.nx_COS_orders_id left join nx_community_goods as cg on cg.nx_community_goods_id = os.nx_COS_community_goods_id left join nx_customer_user as deliveryUser on deliveryUser.nx_CU_user_id = o.nx_CO_delivery_user_id left join nx_customer as deliveryCus on deliveryCus.nx_customer_id = deliveryUser.nx_CU_customer_id left join nx_customer_user_goods as ncug on ncug.nx_CUG_community_goods_id = os.nx_COS_community_goods_id and nx_CUG_user_id = os.nx_COS_order_user_id left join nx_customer_user_address as ncua on ncua.nx_customer_user_address_id = o.nx_CO_delivery_address_id
and o.nx_CO_community_id = #{commId}
and o.nx_CO_status < #{xiaoyuStatus}
and o.nx_CO_status = #{status}
and o.nx_CO_type = #{type}
and o.nx_CO_user_id = #{deliveryUserId}
and o.nx_community_orders_id = #{id}
and o.nx_CO_desk_id = #{deskId}

